package com.promonts.repository;import com.promonts.domain.course.Course;import com.promonts.domain.user.User;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.stereotype.Repository;import java.util.List;import java.util.Optional;@Repository public interface CourseRepository extends JpaRepository<Course, Long> { List<Course> findByProfessor(User professor); Optional<Course> findByCode(String code); List<Course> findBySemesterAndYear(String semester, Integer year); }
